:root {
  --card-bg: #2d1a2e;
  --card-border: #6b3a6e;
  --header-bg: #3d1f3f;
  --accent: #c4587a;
  --accent-light: #e88fa5;
  --gold: #d4a843;
  --badge-bg: #7a2040;
  --badge-text: #f5c4d0;
  --wine-name-color: #f0e6f1;
  --label-color: #c9a8cc;
  --score-color: #e0d0e2;
  --bar-bg: #4a2a4d;
  --bar-aroma: #c4587a;
  --bar-body: #9b4f8e;
  --bar-tannin: #7a6bbf;
  --bar-finish: #d4a843;
  --tag-bg: #4a2040;
  --tag-text: #f0c8d4;
  --tag-border: #7a3a5a;
  --footer-border: #4a2a4d;
  --score-big: #d4a843;
  --meta-color: #a888aa;
}

.card {
  background: var(--card-bg);
  border: 2px solid var(--card-border);
  border-radius: 16px;
  padding: 18px 20px;
  width: 460px;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.wine-label {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.vintage {
  font-size: 22px;
  font-weight: 700;
  color: var(--gold);
  line-height: 1;
}

.region {
  font-size: 12px;
  font-weight: 400;
  color: var(--label-color);
  letter-spacing: 0.04em;
}

.wine-badge {
  background: var(--badge-bg);
  color: var(--badge-text);
  font-size: 12px;
  font-weight: 600;
  padding: 4px 12px;
  border-radius: 20px;
  border: 1px solid var(--accent);
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.wine-name {
  font-size: 18px;
  font-weight: 700;
  color: var(--wine-name-color);
  line-height: 1.2;
}

.tasting-grid {
  display: flex;
  flex-direction: column;
  gap: 8px;
  background: var(--header-bg);
  border-radius: 10px;
  padding: 12px 14px;
}

.taste-item {
  display: flex;
  align-items: center;
  gap: 10px;
}

.taste-label {
  font-size: 12px;
  font-weight: 600;
  color: var(--label-color);
  width: 46px;
  flex-shrink: 0;
}

.taste-bar {
  flex: 1;
  height: 7px;
  background: var(--bar-bg);
  border-radius: 4px;
  overflow: hidden;
}

.taste-fill {
  height: 100%;
  border-radius: 4px;
}

.aroma-fill {
  width: 87%;
  background: var(--bar-aroma);
}

.body-fill {
  width: 72%;
  background: var(--bar-body);
}

.tannin-fill {
  width: 65%;
  background: var(--bar-tannin);
}

.finish-fill {
  width: 91%;
  background: var(--bar-finish);
}

.taste-score {
  font-size: 12px;
  font-weight: 700;
  color: var(--score-color);
  width: 24px;
  text-align: right;
  flex-shrink: 0;
}

.notes-section {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.notes-title {
  font-size: 11px;
  font-weight: 700;
  color: var(--label-color);
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.notes-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.tag {
  background: var(--tag-bg);
  color: var(--tag-text);
  font-size: 12px;
  font-weight: 500;
  padding: 4px 10px;
  border-radius: 6px;
  border: 1px solid var(--tag-border);
}

.card-footer {
  display: flex;
  align-items: center;
  gap: 16px;
  padding-top: 12px;
  border-top: 1px solid var(--footer-border);
}

.score-block {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
  flex-shrink: 0;
}

.score-num {
  font-size: 32px;
  font-weight: 800;
  color: var(--score-big);
  line-height: 1;
}

.score-label {
  font-size: 10px;
  font-weight: 600;
  color: var(--label-color);
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.footer-meta {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.serve-temp {
  font-size: 13px;
  font-weight: 600;
  color: var(--accent-light);
}

.pair-label {
  font-size: 12px;
  font-weight: 400;
  color: var(--meta-color);
}
